import React, { useState } from 'react';
import ReactMarkdown from 'react-markdown';
import remarkGfm from 'remark-gfm';
import rehypeSanitize from 'rehype-sanitize';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';
import { CopyOutlined, CheckOutlined, InfoCircleOutlined, CheckCircleOutlined, ExclamationCircleOutlined, WarningOutlined, CloseCircleOutlined } from '@ant-design/icons';
import { message, Image } from 'antd';
import { Mermaid } from './Mermaid';

const alertConfig: Record<string, any> = {
  NOTE: { color: '#0969da', icon: <InfoCircleOutlined />, title: 'Note' },
  TIP: { color: '#1a7f37', icon: <CheckCircleOutlined />, title: 'Tip' },
  IMPORTANT: { color: '#8250df', icon: <ExclamationCircleOutlined />, title: 'Important' },
  WARNING: { color: '#9a6700', icon: <WarningOutlined />, title: 'Warning' },
  CAUTION: { color: '#d1242f', icon: <CloseCircleOutlined />, title: 'Caution' },
};

const SAFE_URL_PROTOCOLS = new Set(['http:', 'https:', 'mailto:', 'tel:']);
const SAFE_DATA_IMAGE_PATTERN =
  /^data:image\/(png|jpe?g|gif|webp|bmp);base64,[a-z0-9+/=\s]+$/i;

const safeUrlTransform = (value: string): string => {
  const trimmed = value.trim();
  if (!trimmed) return '';

  if (
    trimmed.startsWith('/') ||
    trimmed.startsWith('./') ||
    trimmed.startsWith('../') ||
    trimmed.startsWith('#')
  ) {
    return value;
  }

  if (SAFE_DATA_IMAGE_PATTERN.test(trimmed)) {
    return value;
  }

  try {
    const baseUrl = globalThis.location?.origin || 'http://localhost';
    const parsed = new URL(trimmed, baseUrl);
    return SAFE_URL_PROTOCOLS.has(parsed.protocol) ? value : '';
  } catch {
    return '';
  }
};

const extractAlert = (children: React.ReactNode): { type: string | null, newChildren: React.ReactNode } => {
  let type: string | null = null;
  let textFound = false;

  const processNode = (node: React.ReactNode): React.ReactNode => {
    if (typeof node === 'string') {
      if (node.trim() === '') return node;
      if (!textFound) {
        textFound = true;
        const match = node.match(/^\[!(NOTE|TIP|IMPORTANT|WARNING|CAUTION)\]\s*/i);
        if (match) {
          type = match[1].toUpperCase();
          return node.substring(match[0].length);
        }
      }
      return node;
    }

    if (React.isValidElement(node)) {
      if (node.props && (node.props as any).children) {
        const newPropsChildren = React.Children.map((node.props as any).children, processNode);
        return React.cloneElement(node, { ...(node.props as any), children: newPropsChildren } as any);
      }
    }

    if (Array.isArray(node)) {
      return node.map(processNode);
    }

    return node;
  };

  const newChildren = React.Children.map(children, processNode);
  return { type, newChildren };
};

interface MarkdownViewerProps {
  content: string;
}

const CodeRenderer = ({ className, children, ...props }: any) => {
  const match = /language-(\w+)/.exec(className || '');
  const language = match ? match[1] : '';
  const codeString = String(children).replace(/\n$/, '');
  const [copied, setCopied] = useState(false);

  const handleCopy = () => {
    if (navigator.clipboard && window.isSecureContext) {
      navigator.clipboard.writeText(codeString)
        .then(() => {
          setCopied(true);
          message.success('已复制到剪贴板');
          setTimeout(() => setCopied(false), 2000);
        })
        .catch(() => message.error('复制失败'));
    } else {
      const textArea = document.createElement("textarea");
      textArea.value = codeString;
      textArea.style.position = "absolute";
      textArea.style.left = "-999999px";
      document.body.prepend(textArea);
      textArea.select();
      try {
        document.execCommand('copy');
        setCopied(true);
        message.success('已复制到剪贴板');
        setTimeout(() => setCopied(false), 2000);
      } catch {
        message.error('复制失败');
      } finally {
        textArea.remove();
      }
    }
  };

  const isBlock = match || String(children).includes('\n');

  if (isBlock && language === 'mermaid') {
    return <Mermaid chart={codeString} />;
  }

  return isBlock ? (
    <div style={{ position: 'relative', marginTop: 16, marginBottom: 16, borderRadius: 8, overflow: 'hidden', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}>
      <div style={{
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        background: '#1e1e1e',
        color: '#888',
        padding: '4px 12px',
        fontSize: 12,
        fontFamily: 'Consolas, Monaco, "Courier New", monospace',
        borderBottom: '1px solid #333'
      }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
          <span style={{ width: 10, height: 10, borderRadius: '50%', background: '#ff5f56' }}></span>
          <span style={{ width: 10, height: 10, borderRadius: '50%', background: '#ffbd2e' }}></span>
          <span style={{ width: 10, height: 10, borderRadius: '50%', background: '#27c93f' }}></span>
          <span style={{ marginLeft: 8, fontSize: 13, color: '#a0a0a0', fontWeight: 600 }}>{language || 'text'}</span>
        </div>

        <div
          onClick={handleCopy}
          style={{
            cursor: 'pointer',
            display: 'flex',
            alignItems: 'center',
            gap: 4,
            opacity: 0.8,
            transition: 'opacity 0.2s',
          }}
          onMouseEnter={(e) => (e.currentTarget.style.opacity = '1')}
          onMouseLeave={(e) => (e.currentTarget.style.opacity = '0.8')}
        >
          {copied ? <CheckOutlined style={{ color: '#27c93f' }} /> : <CopyOutlined />}
          <span style={{ userSelect: 'none' }}>{copied ? 'Copied' : 'Copy'}</span>
        </div>
      </div>

      <SyntaxHighlighter
        {...props}
        style={vscDarkPlus as any}
        language={language || 'text'}
        PreTag="div"
        customStyle={{
          margin: 0,
          borderRadius: '0 0 8px 8px',
          padding: '16px',
          fontSize: '14px',
          lineHeight: '1.5',
        }}
        showLineNumbers={true}
        wrapLines={true}
      >
        {codeString}
      </SyntaxHighlighter>
    </div>
  ) : (
    <code className={`markdown-inline-code ${className || ''}`} {...props}>
      {children}
    </code>
  );
};

export const MarkdownViewer: React.FC<MarkdownViewerProps> = ({ content }) => {
  return (
    <div className="markdown-viewer">
      <ReactMarkdown
        urlTransform={safeUrlTransform}
        remarkPlugins={[remarkGfm]}
        rehypePlugins={[rehypeSanitize]}
        components={{
          blockquote({ children, ...props }: any) {
            const { type, newChildren } = extractAlert(children);

            if (type && alertConfig[type]) {
              const config = alertConfig[type];
              return (
                <div style={{
                  borderLeft: `4px solid ${config.color}`,
                  padding: '8px 16px',
                  margin: '16px 0',
                  color: '#57606a',
                  backgroundColor: 'transparent',
                }} className={`markdown-alert markdown-alert-${type.toLowerCase()}`}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '8px', color: config.color, fontWeight: 600, marginBottom: '8px', fontSize: '14px' }}>
                    {config.icon}
                    <span>{config.title}</span>
                  </div>
                  <div className="markdown-alert-content" style={{ margin: 0 }}>
                    {newChildren}
                  </div>
                </div>
              );
            }
            return <blockquote {...props}>{children}</blockquote>;
          },
          code: CodeRenderer,
          img({ src, alt }: any) {
            return (
              <Image
                src={src || ''}
                alt={alt || '图片'}
                style={{ maxWidth: '100%', borderRadius: 8, cursor: 'pointer' }}
                preview={{ mask: '点击放大' }}
                fallback="data:image/svg+xml;base64,"
              />
            );
          }
        }}
      >
        {content}
      </ReactMarkdown>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import mermaid from 'mermaid';
import { Spin } from 'antd';
import { LoadingOutlined } from '@ant-design/icons';

mermaid.initialize({
  startOnLoad: false,
  theme: 'default', // 改为默认的浅色主题，适应明亮的页面背景
  securityLevel: 'strict',
  fontFamily: 'inherit'
});

const sanitizeMermaidSvg = (svg: string): string => {
  // Mermaid is initialized with securityLevel: 'strict', which already
  // mitigates most XSS risks. DOMParser with 'image/svg+xml' is too strict
  // and frequently throws parsererror on perfectly valid Mermaid SVGs
  // due to HTML inside <foreignObject>. 

  // As a fallback defense-in-depth, we do a basic string replacement
  // to remove any script tags or javascript: hrefs that might have somehow bypassed Mermaid.
  let cleanSvg = svg;

  // Remove <script> tags
  cleanSvg = cleanSvg.replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '');

  // Remove javascript: and data:text/html links
  cleanSvg = cleanSvg.replace(/href\s*=\s*["']\s*(javascript:|data:text\/html)[^"']*["']/gi, 'href="#"');
  cleanSvg = cleanSvg.replace(/xlink:href\s*=\s*["']\s*(javascript:|data:text\/html)[^"']*["']/gi, 'xlink:href="#"');

  // Remove inline on* event handlers
  cleanSvg = cleanSvg.replace(/\bon[a-z]+\s*=\s*["'][^"']*["']/gi, '');

  return cleanSvg;
};

interface MermaidProps {
  chart: string;
}

export const Mermaid: React.FC<MermaidProps> = ({ chart }) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [svgContent, setSvgContent] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string>('');

  useEffect(() => {
    let isMounted = true;
    const renderChart = async () => {
      setLoading(true);
      setError('');
      try {
        const id = `mermaid-${Math.random().toString(36).substr(2, 9)}`;
        const { svg } = await mermaid.render(id, chart);
        if (isMounted) {
          setSvgContent(sanitizeMermaidSvg(svg));
          setLoading(false);
        }
      } catch (err: any) {
        console.error('Mermaid rendering failed:', err);
        if (isMounted) {
          setError(err?.message || '图表渲染失败');
          setLoading(false);
        }
      }
    };

    if (chart) {
      renderChart();
    }

    return () => {
      isMounted = false;
    };
  }, [chart]);

  return (
    <div 
      className="mermaid-wrapper" 
      ref={containerRef}
      style={{
        background: '#f8f9fa', // 柔和的浅灰背景
        border: '1px solid #ebedf0', // 细微的边框
        padding: '20px',
        borderRadius: '8px',
        margin: '16px 0',
        display: 'block', // 移除 flex，避免 flex item 压缩 SVG
        minHeight: '100px',
        overflowX: 'auto', // 允许横向滚动
        boxShadow: '0 2px 8px rgba(0,0,0,0.04)', // 极其轻微的阴影
        textAlign: 'center' // 让内容居中
      }}
    >
      {loading && <Spin indicator={<LoadingOutlined style={{ fontSize: 24, color: '#6366f1' }} spin />} tip="正在渲染图表..." />}
      {error && (
        <div style={{ color: '#ff4d4f', fontFamily: 'monospace', whiteSpace: 'pre-wrap', textAlign: 'left', width: '100%' }}>
          {error}
        </div>
      )}
      {!loading && !error && (
        <div 
          style={{ minWidth: 'max-content', margin: '0 auto' }}
          dangerouslySetInnerHTML={{ __html: svgContent }} 
        />
      )}
    </div>
  );
};

import React from 'react';
import { useAuthStore } from '../stores/authStore';

interface RequirePermissionProps {
  permissions: string[];
  children: React.ReactNode;
}

export const RequirePermission: React.FC<RequirePermissionProps> = ({ permissions, children }) => {
  const { user } = useAuthStore();

  if (!user || !user.role) {
    return null;
  }

  const roleObj: any = user.role;
  // 超级管理员/系统管理员天然拥有全部展示权 (或者叫 admin 的用户)
  if (roleObj.name === 'admin' || user.username === 'admin') {
    return <>{children}</>;
  }

  // 临时外部用户无任何常规操作界面展示权
  if (roleObj.name === 'external' || roleObj === 'external') {
    return null;
  }

  const userPermissions = roleObj.permissions || [];

  // 检查是否具备所需权限之一
  const hasPermission = permissions.some((requiredCode) => {
    return userPermissions.some((p: any) => {
      const pCode = p.code || `${p.resource}:${p.action}`;
      return pCode === requiredCode;
    });
  });

  if (!hasPermission) {
    return null;
  }

  return <>{children}</>;
};

