import React, { useState, useEffect } from 'react';
import { Card, Button, Upload, Table, Tag, message, Space, Empty, Alert, Tree } from 'antd';
import { UploadOutlined, ReloadOutlined, FileExcelOutlined, CheckCircleOutlined } from '@ant-design/icons';
import { categoryAPI } from '../../../services/api';

const CategoryTab: React.FC = () => {
  const [categories, setCategories] = useState<any[]>([]);
  const [treeData, setTreeData] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [viewMode, setViewMode] = useState<'tree' | 'table'>('tree');

  const loadData = async () => {
    setLoading(true);
    try {
      const [allRes, treeRes] = await Promise.all([
        categoryAPI.getAll(),
        categoryAPI.getTree(),
      ]);
      if ((allRes as any).code === 0) setCategories((allRes as any).data || []);
      if ((treeRes as any).code === 0) setTreeData((treeRes as any).data || []);
    } catch {} finally { setLoading(false); }
  };

  useEffect(() => { loadData(); }, []);

  const handleUpload = async (file: File) => {
    const formData = new FormData();
    formData.append('file', file);
    setUploading(true);
    try {
      const res: any = await categoryAPI.importExcel(formData);
      if (res.code === 0) {
        message.success(res.message || `成功导入 ${res.data?.imported} 条分类`);
        loadData();
      } else {
        message.error(res.message || '导入失败');
      }
    } catch (err: any) {
//       message.error(err.response?.data?.message || '导入失败'); // Removed by global interceptor refactor
    } finally { setUploading(false); }
    return false; // prevent default upload
  };

  // Convert tree data for Ant Design Tree component
  const convertToAntTree = (nodes: any[]): any[] => {
    return nodes.map((node, i) => ({
      title: (
        <span style={{ fontSize: 13 }}>
          {!node.children || node.children.length === 0
            ? <Tag color="blue" style={{ margin: 0 }}>{node.label}</Tag>
            : <span style={{ fontWeight: 500 }}>{node.label}</span>
          }
          {node.children && <span style={{ color: 'var(--text-muted)', fontSize: 11, marginLeft: 6 }}>({node.children.length})</span>}
        </span>
      ),
      key: `${i}-${node.value}`,
      children: node.children ? convertToAntTree(node.children.map((c: any, j: number) => ({ ...c, _parentIdx: i, _idx: j }))) : undefined,
    }));
  };

  const columns = [
    { title: '支持类型', dataIndex: 'level1', width: 150, render: (v: string) => <Tag color="purple">{v}</Tag> },
    { title: '技术方向', dataIndex: 'level2', width: 200, render: (v: string) => <Tag color="blue">{v}</Tag> },
    { title: '品牌', dataIndex: 'level3', render: (v: string) => <Tag color="cyan">{v}</Tag> },
  ];

  // Stats
  const l1Count = new Set(categories.map(c => c.level1)).size;
  const l2Count = new Set(categories.map(c => `${c.level1}/${c.level2}`)).size;

  return (
    <div>
      <Alert
        type="info"
        showIcon
        icon={<FileExcelOutlined />}
        message="工单分类管理"
        description="上传 Excel 文件定义三级工单分类（支持类型 → 技术方向 → 品牌）。重新导入将覆盖现有分类定义。Excel 格式：第一行为表头，后续行依次为三列分类数据。"
        style={{ marginBottom: 16, borderRadius: 8 }}
      />

      <Card size="small" style={{ borderRadius: 12, border: '1px solid var(--border)', marginBottom: 16 }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', flexWrap: 'wrap', gap: 12 }}>
          <Space>
            <Upload
              accept=".xlsx,.xls"
              showUploadList={false}
              beforeUpload={handleUpload}
            >
              <Button type="primary" icon={<UploadOutlined />} loading={uploading}>
                {categories.length > 0 ? '重新导入 Excel' : '导入 Excel'}
              </Button>
            </Upload>
            <Button icon={<ReloadOutlined />} onClick={loadData} loading={loading}>刷新</Button>
          </Space>

          {categories.length > 0 && (
            <Space size={16}>
              <span style={{ fontSize: 12, color: 'var(--text-muted)' }}>
                <CheckCircleOutlined style={{ color: '#059669', marginRight: 4 }} />
                共 <b>{categories.length}</b> 条 | {l1Count} 个支持类型 | {l2Count} 个技术方向
              </span>
              <Button.Group size="small">
                <Button type={viewMode === 'tree' ? 'primary' : 'default'} onClick={() => setViewMode('tree')}>树视图</Button>
                <Button type={viewMode === 'table' ? 'primary' : 'default'} onClick={() => setViewMode('table')}>表格视图</Button>
              </Button.Group>
            </Space>
          )}
        </div>
      </Card>

      {categories.length === 0 ? (
        <Card style={{ borderRadius: 12, border: '1px solid var(--border)' }}>
          <Empty
            image={Empty.PRESENTED_IMAGE_SIMPLE}
            description="尚未导入工单分类数据"
          >
            <Upload accept=".xlsx,.xls" showUploadList={false} beforeUpload={handleUpload}>
              <Button type="primary" icon={<UploadOutlined />} loading={uploading}>立即导入</Button>
            </Upload>
          </Empty>
        </Card>
      ) : viewMode === 'tree' ? (
        <Card size="small" style={{ borderRadius: 12, border: '1px solid var(--border)' }} bodyStyle={{ padding: '8px 16px' }}>
          <Tree
            treeData={convertToAntTree(treeData)}
            defaultExpandedKeys={treeData.map((_, i) => `${i}-${treeData[i]?.value}`)}
            selectable={false}
            showLine
            style={{ background: 'transparent' }}
          />
        </Card>
      ) : (
        <Card size="small" style={{ borderRadius: 12, border: '1px solid var(--border)' }} bodyStyle={{ padding: 0 }}>
          <Table
            dataSource={categories}
            columns={columns}
            rowKey="id"
            size="small"
            pagination={{ pageSize: 20, showTotal: t => `共 ${t} 条` }}
            scroll={{ x: 500 }}
          />
        </Card>
      )}
    </div>
  );
};

export default CategoryTab;

import React, { useEffect, useState } from 'react';
import {
  Form, InputNumber, Button, Card, Alert, Descriptions, Badge, Spin, message, Tooltip, Input, Radio
} from 'antd';
import {
  ThunderboltOutlined, ReloadOutlined, InfoCircleOutlined, WarningOutlined, CloudServerOutlined
} from '@ant-design/icons';
import { settingsAPI } from '../../../services/api';

interface WorkerConfig {
  concurrency: number;
  maxResumeAttempts?: number;
  cosSecretId?: string;
  cosSecretKey?: string;
  cosBucket?: string;
  cosRegion?: string;
  storageProvider?: string;
  s3Endpoint?: string;
  s3AccessKey?: string;
  s3SecretKey?: string;
  s3Bucket?: string;
  s3Region?: string;
}

const CodexConfigTab: React.FC = () => {
  const [form] = Form.useForm();
  const [loading, setLoading] = useState(false);
  const [initLoading, setInitLoading] = useState(true);
  const [workerConfig, setWorkerConfig] = useState<WorkerConfig | null>(null);
  const [provider, setProvider] = useState<'tencent' | 's3'>('tencent');
  const [lastResult, setLastResult] = useState<any>(null);

  // 加载当前配置（直接从 Worker 读，两个前端显示一致）
  useEffect(() => {
    const load = async () => {
      try {
        const res: any = await settingsAPI.getCodexConfig();
        if (res.code === 0 && res.data) {
          const concurrency = res.data.concurrency ?? 2;
          const maxResumeAttempts = res.data.maxResumeAttempts ?? 3;
          const { cosSecretId, cosSecretKey, cosBucket, cosRegion, storageProvider, s3Endpoint, s3AccessKey, s3SecretKey, s3Bucket, s3Region } = res.data;
          const prov = storageProvider || 'tencent';
          setProvider(prov);
          form.setFieldsValue({ 
            concurrency, maxResumeAttempts, 
            cosSecretId, cosSecretKey, cosBucket, cosRegion,
            storageProvider: prov, s3Endpoint, s3AccessKey, s3SecretKey, s3Bucket, s3Region 
          });
          setWorkerConfig({ 
            concurrency, maxResumeAttempts, 
            cosSecretId, cosSecretKey, cosBucket, cosRegion,
            storageProvider: prov, s3Endpoint, s3AccessKey, s3SecretKey, s3Bucket, s3Region 
          });
        }
      } catch {
        form.setFieldsValue({ concurrency: 2, maxResumeAttempts: 3 });
        setWorkerConfig({ concurrency: 2, maxResumeAttempts: 3 });
      } finally {
        setInitLoading(false);
      }
    };
    load();
  }, []);

  const handleSave = async (values: any) => {
    setLoading(true);
    setLastResult(null);
    try {
      const res: any = await (settingsAPI as any).saveCodexConfig(values);
      if (res.code === 0) {
        setLastResult(res.data);
        setWorkerConfig({ ...workerConfig, ...values });
        if (res.data?.restartRequired) {
          message.warning('并发线程数已保存，请在东京服务器执行 pm2 restart codex-worker 后生效');
        } else {
          message.success('AI 协作配置已保存并即时生效');
        }
      } else {
        message.error(res.message || '保存失败');
      }
    } catch {
      message.error('保存失败，请检查网络连接');
    } finally {
      setLoading(false);
    }
  };

  if (initLoading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', paddingTop: 60 }}>
        <Spin tip="加载配置中..." />
      </div>
    );
  }

  return (
    <div style={{ padding: 24, maxWidth: 720 }}>
      <h3 style={{ fontWeight: 600, marginBottom: 4 }}>🤖 AI 协作引擎配置</h3>
      <p style={{ color: 'var(--text-secondary)', marginBottom: 24, fontSize: 13 }}>
        控制东京节点 Codex Worker 的并发和容错行为
      </p>

      {/* 当前生效状态 */}
      {workerConfig && (
        <Card
          size="small"
          style={{ marginBottom: 24, borderRadius: 10, border: '1px solid var(--border)' }}
          title={<span style={{ fontWeight: 600 }}>📊 Worker 当前运行状态</span>}
        >
          <Descriptions size="small" column={2}>
            <Descriptions.Item label="并发线程数">
              <Badge status="processing" text={`${workerConfig.concurrency} 个`} />
            </Descriptions.Item>
            <Descriptions.Item label="自动续跑次数">
              <Badge status="success" text={`${workerConfig.maxResumeAttempts ?? 3} 次`} />
            </Descriptions.Item>
          </Descriptions>
        </Card>
      )}

      <Form form={form} layout="vertical" onFinish={handleSave}>
        <Card
          size="small"
          style={{ marginBottom: 20, borderRadius: 10, border: '1px solid var(--border)' }}
          title={
            <span style={{ fontWeight: 600 }}>
              <CloudServerOutlined style={{ color: '#1677ff', marginRight: 6 }} />
              云存储配置 (Worker 专属)
            </span>
          }
        >
          <Alert
            type="info"
            showIcon
            message="专属存储空间"
            description="这些配置专用于存放 AI 执行过程中的上下文、附件及生成产物，与主站隔离。修改后也会自动重启 Worker 生效。"
            style={{ marginBottom: 16 }}
          />

          <Form.Item name="storageProvider" style={{ marginBottom: 16 }}>
            <Radio.Group onChange={(e) => setProvider(e.target.value)}>
              <Radio.Button value="tencent">☁️ 腾讯云 (COS)</Radio.Button>
              <Radio.Button value="s3">🌐 首云 (S3兼容)</Radio.Button>
            </Radio.Group>
          </Form.Item>

          {provider === 'tencent' && (
            <>
              <Form.Item label="SecretId" name="cosSecretId" rules={[{ required: provider === 'tencent', message: '请输入 SecretId' }]}>
                <Input placeholder="输入腾讯云 API 密钥的 SecretId" />
              </Form.Item>
              <Form.Item label="SecretKey" name="cosSecretKey" rules={[{ required: provider === 'tencent', message: '请输入 SecretKey' }]}>
                <Input.Password placeholder="输入腾讯云 API 密钥的 SecretKey（留空保持不变）" />
              </Form.Item>
              <Form.Item label="存储桶名称 (Bucket)" name="cosBucket" rules={[{ required: provider === 'tencent', message: '请输入存储桶名称' }]}>
                <Input placeholder="如: codex-worker-1234567890" />
              </Form.Item>
              <Form.Item label="所属地域 (Region)" name="cosRegion" rules={[{ required: provider === 'tencent', message: '请输入所属地域' }]}>
                <Input placeholder="如: ap-guangzhou" />
              </Form.Item>
            </>
          )}
          {provider === 's3' && (
            <>
              <Form.Item label="Endpoint (访问域名)" name="s3Endpoint" rules={[{ required: provider === 's3', message: '请输入 Endpoint' }]}>
                <Input placeholder="例如: https://s3-cn-beijing.capitalonline.net" />
              </Form.Item>
              <Form.Item label="Access Key (AK)" name="s3AccessKey" rules={[{ required: provider === 's3', message: '请输入 Access Key' }]}>
                <Input placeholder="请输入 Access Key" />
              </Form.Item>
              <Form.Item label="Secret Key (SK)" name="s3SecretKey" rules={[{ required: provider === 's3', message: '请输入 Secret Key' }]}>
                <Input.Password placeholder="请输入 Secret Key（留空保持不变）" />
              </Form.Item>
              <Form.Item label="Bucket (存储桶名称)" name="s3Bucket" rules={[{ required: provider === 's3', message: '请输入存储桶名称' }]}>
                <Input placeholder="my-s3-bucket" />
              </Form.Item>
              <Form.Item label="Region (所属地域)" name="s3Region" extra="可选，留空自动使用 us-east-1">
                <Input placeholder="留空即可，首云等 S3 兼容服务通常不需要" />
              </Form.Item>
            </>
          )}
        </Card>

        {/* 并发线程数 */}
        <Card
          size="small"
          style={{ marginBottom: 20, borderRadius: 10, border: '1px solid var(--border)' }}
          title={
            <span style={{ fontWeight: 600 }}>
              <ThunderboltOutlined style={{ color: '#f59e0b', marginRight: 6 }} />
              并发线程数
            </span>
          }
        >
          <Alert
            type="warning"
            showIcon
            icon={<WarningOutlined />}
            message="修改此项需重启 Worker"
            description={
              <span>
                并发数由 BullMQ 在进程启动时固定，修改后需在东京服务器执行：
                <code style={{ background: '#1e293b', color: '#e2e8f0', padding: '2px 6px', borderRadius: 4, marginLeft: 6 }}>
                  pm2 restart codex-worker
                </code>
              </span>
            }
            style={{ marginBottom: 16 }}
          />
          <Form.Item
            name="concurrency"
            label={
              <span>
                最大并发任务数
                <Tooltip title="同时执行的 Codex AI 任务数量。值越高吞吐越大，但占用内存也越多（推荐 2~4）">
                  <InfoCircleOutlined style={{ marginLeft: 6, color: 'var(--text-secondary)' }} />
                </Tooltip>
              </span>
            }
            rules={[{ required: true, type: 'number', min: 1, max: 16, message: '请输入 1~16 之间的整数' }]}
          >
            <InputNumber
              min={1}
              max={16}
              style={{ width: 160 }}
              addonAfter="个线程"
            />
          </Form.Item>
          <div style={{ fontSize: 12, color: 'var(--text-secondary)' }}>
            💡 当前服务器（东京 4C8G）推荐并发数：2~3
          </div>
        </Card>


        {/* 自动断点续跑次数 */}
        <Card
          size="small"
          style={{ marginBottom: 20, borderRadius: 10, border: '1px solid var(--border)' }}
          title={
            <span style={{ fontWeight: 600 }}>
              <ReloadOutlined style={{ color: '#8b5cf6', marginRight: 6 }} />
              自动断点续跑次数
            </span>
          }
        >
          <Alert
            type="info"
            showIcon
            message="修改后需重启 Worker 生效"
            description="PPT 任务因断线/崩溃中断后，系统会自动从断点恢复执行。此项控制最大自动恢复尝试次数，达到上限后任务暂停等待人工介入。"
            style={{ marginBottom: 16 }}
          />
          <Form.Item
            name="maxResumeAttempts"
            label={
              <span>
                最大自动续跑次数
                <Tooltip title="PPT 任务因 WebSocket 断线、进程重启等原因中断后，系统自动从 manifest 断点恢复的最大次数。超过此次数后任务暂停，需手动决定是否继续。">
                  <InfoCircleOutlined style={{ marginLeft: 6, color: 'var(--text-secondary)' }} />
                </Tooltip>
              </span>
            }
            rules={[{ required: true, type: 'number', min: 1, max: 20, message: '请输入 1~20 之间的整数' }]}
          >
            <InputNumber
              min={1}
              max={20}
              style={{ width: 160 }}
              addonAfter="次"
            />
          </Form.Item>
          <div style={{ fontSize: 12, color: 'var(--text-secondary)' }}>
            💡 推荐值：5~10。网络不稳定时建议适当调高，避免频繁暂停。
          </div>
        </Card>

        {/* 保存结果反馈 */}
        {lastResult && (
          <Alert
            type={lastResult.restartRequired ? 'warning' : 'success'}
            showIcon
            message={lastResult.note}
            style={{ marginBottom: 20 }}
            closable
            onClose={() => setLastResult(null)}
          />
        )}

        <Form.Item>
          <Button type="primary" htmlType="submit" loading={loading} size="middle">
            保存 AI 协作配置
          </Button>
        </Form.Item>
      </Form>
    </div>
  );
};

export default CodexConfigTab;

import React, { useState } from 'react';
import { Select, Input, Button, Form, message, Alert, Row, Col } from 'antd';

const { TextArea } = Input;
const { Option } = Select;

const userSyncTemplate = `[
  {
    "employeeId": "TEST_001",
    "realName": "测试员工A",
    "email": "test_a@company.com",
    "phone": "13800138000",
    "department": "技术部",
    "position": "前端工程师",
    "isActive": 1
  }
]`;

const ticketPushTemplate = `{
  "title": "测试工单：办公网异常",
  "description": "无法连接内部网络",
  "serviceNo": "OMM_TEST_1001",
  "customerName": "财务部",
  "creatorEmployeeId": "TEST_001",
  "assigneeEmployeeId": "TEST_001",
  "type": "network",
  "status": "in_progress"
}`;

export const ExtSyncTestTab: React.FC = () => {
  const [token, setToken] = useState('');
  const [apiType, setApiType] = useState('users');
  const [payload, setPayload] = useState(userSyncTemplate);
  const [response, setResponse] = useState('');
  const [loading, setLoading] = useState(false);

  const handleApiChange = (value: string) => {
    setApiType(value);
    setPayload(value === 'users' ? userSyncTemplate : ticketPushTemplate);
    setResponse('');
  };

  const handleSend = async () => {
    if (!token) {
      message.error('请提供 SERVICE_TOKEN');
      return;
    }

    let parsedData;
    try {
      parsedData = JSON.parse(payload);
    } catch (e) {
      message.error('请求体 JSON 格式不正确');
      return;
    }

    setLoading(true);
    setResponse('发送中...');

    try {
      const endpoint = apiType === 'users' ? '/api/ext/users/sync' : '/api/ext/tickets';

      const res = await fetch(endpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify(parsedData)
      });

      const data = await res.json();
      setResponse(JSON.stringify(data, null, 2));

      if (res.ok) {
        message.success('请求成功！');
      } else {
        message.error(`请求失败: ${res.status} ${res.statusText}`);
      }
    } catch (err: any) {
      setResponse(`网络错误: ${err.message}`);
      message.error('网络请求失败');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: 24, minHeight: 400 }}>
      <Alert
        message="中台对接沙盒测试"
        description="此模块将绕过当前用户的登录态，使用输入的 SERVICE_TOKEN 直接模拟外部系统向底层核心接口发起的请求。仅供调试与验收使用。"
        type="info"
        showIcon
        style={{ marginBottom: 20 }}
      />

      <Form layout="vertical">
        <Row gutter={16}>
          <Col xs={24} md={12}>
            <Form.Item label="SERVICE_TOKEN 鉴权密钥" required>
              <Input.Password
                placeholder="输入管理员提供的环境专属 Token"
                value={token}
                onChange={(e) => setToken(e.target.value)}
              />
            </Form.Item>
          </Col>
          <Col xs={24} md={12}>
            <Form.Item label="选择测试接口" required>
              <Select value={apiType} onChange={handleApiChange}>
                <Option value="users">人员组织架构同步 (POST /api/ext/users/sync)</Option>
                <Option value="tickets">业务工单推送 (POST /api/ext/tickets)</Option>
              </Select>
            </Form.Item>
          </Col>
        </Row>

        <Row gutter={16}>
          <Col xs={24} md={12}>
            <Form.Item label="请求报文 (Request JSON)">
              <TextArea
                rows={12}
                value={payload}
                onChange={(e) => setPayload(e.target.value)}
                style={{ fontFamily: 'monospace' }}
              />
            </Form.Item>
            <Button type="primary" onClick={handleSend} loading={loading} block>
              发送模拟请求
            </Button>
          </Col>
          <Col xs={24} md={12}>
            <Form.Item label="响应结果 (Response JSON)">
              <TextArea
