import React, { useState, useEffect, useCallback } from 'react';
import { Card, Tag, Button, Empty, Segmented, message, Row, Col, Modal, Form, Input, Select, Badge, Cascader } from 'antd';
import {
  CheckOutlined, PlusOutlined, FileTextOutlined, CustomerServiceOutlined, TeamOutlined, LoginOutlined,
  MessageOutlined, RobotOutlined
} from '@ant-design/icons';
import { ticketsAPI, usersAPI, categoryAPI } from '../../services/api';
import { useAuthStore } from '../../stores/authStore';
import { useSocketStore } from '../../stores/socketStore';
import { useNavigate } from 'react-router-dom';

const { Option } = Select;

const statusMap: Record<string, { color: string; text: string }> = {
  pending: { color: 'orange', text: '待接单' },
  in_progress: { color: 'blue', text: '服务中' },
  closing: { color: 'volcano', text: '待确认' },
  closed: { color: 'green', text: '已关闭' },
};

const typeMap: Record<string, string> = {
  software: '软件问题', hardware: '硬件问题', network: '网络问题',
  security: '安全问题', database: '数据库', other: '其他',
};

const ProfilePage: React.FC = () => {
  const [tab, setTab] = useState<string>('created');
  const [createdTickets, setCreatedTickets] = useState<any[]>([]);
  const [assignedTickets, setAssignedTickets] = useState<any[]>([]);
  const [participatedTickets, setParticipatedTickets] = useState<any[]>([]);
  const [createModalOpen, setCreateModalOpen] = useState(false);
  const [createForm] = Form.useForm();
  const [assigneeOptions, setAssigneeOptions] = useState<any[]>([]);
  const [assigneeSearching, setAssigneeSearching] = useState(false);
  const [categoryTree, setCategoryTree] = useState<any[]>([]);
  const user = useAuthStore((s) => s.user);
  const navigate = useNavigate();
  const { socket, unreadMap, newTicketIds, clearNewTicket, clearUnread, setMyTicketIds } = useSocketStore();
  let searchTimer: any = null;

  const loadData = useCallback(async () => {
    try {
      const [createdRes, assignedRes, participatedRes] = await Promise.all([
        ticketsAPI.myCreated(),
        ticketsAPI.myAssigned(),
        ticketsAPI.myParticipated(),
      ]);
      const created = (createdRes as any).code === 0 ? ((createdRes as any).data || []) : [];
      const assigned = (assignedRes as any).code === 0 ? ((assignedRes as any).data || []) : [];
      const participated = (participatedRes as any).code === 0 ? ((participatedRes as any).data || []) : [];

      setCreatedTickets(created);
      setAssignedTickets(assigned);
      setParticipatedTickets(participated);

      // 将所有相关工单 ID 同步到 socketStore，供全局 badge 计算使用
      const allIds = [...created, ...assigned, ...participated].map((t: any) => t.id);
      setMyTicketIds(allIds);
    } catch {}
  }, [setMyTicketIds]);

  useEffect(() => { loadData(); }, [loadData]);

  useEffect(() => {
    if (!socket) return;
    const handler = () => loadData();
    socket.on('ticketEvent', handler);
    return () => { socket.off('ticketEvent', handler); };
  }, [socket, loadData]);

  // 加载工单分类树
  useEffect(() => {
    categoryAPI.getTree().then((res: any) => {
      if (res.code === 0 && res.data?.length > 0) setCategoryTree(res.data);
    }).catch(() => {});
  }, []);

  // NEW 标记在用户点击卡片进入工单时清除（renderTicketCard 的 onClick 中已处理）
  // 不再在切换 tab 时自动清除，让用户能看到哪些卡片是新到达的

  const handleAssign = async (id: number) => {
    try {
      const res: any = await ticketsAPI.assign(id);
      if (res.code === 0) { message.success('接单成功'); loadData(); }
} catch (err: any) { /* handled globally */ } // Removed by global interceptor refactor
  };

  const handleCreate = async (values: any) => {
    try {
      const submitData = { ...values };
      if (values.categoryPath && values.categoryPath.length > 0) {
        submitData.category1 = values.categoryPath[0] || '';
        submitData.category2 = values.categoryPath[1] || '';
        submitData.category3 = values.categoryPath[2] || '';
        submitData.type = 'other';
      }
      delete submitData.categoryPath;
      const res: any = await ticketsAPI.create(submitData);
      if (res.code === 0) { message.success('工单创建成功'); setCreateModalOpen(false); createForm.resetFields(); loadData(); }
} catch (err: any) { /* handled globally */ } // Removed by global interceptor refactor
  };

  const handleAssigneeSearch = (value: string) => {
    if (searchTimer) clearTimeout(searchTimer);
    if (!value) { setAssigneeOptions([]); return; }
    searchTimer = setTimeout(async () => {
      setAssigneeSearching(true);
      try {
        const res: any = await usersAPI.search(value);
        if (res.code === 0) {
          setAssigneeOptions(res.data.map((u: any) => ({
            value: u.id,
            label: `${u.realName || u.displayName || u.username} (${u.username})`,
          })));
        }
      } catch {} finally { setAssigneeSearching(false); }
    }, 300);
  };

  // 计算每个 tab 中未读消息总数和新工单数量
  const getTabBadge = (tickets: any[]) => {
    const unreadCount = tickets.reduce((sum, t) => sum + (unreadMap[t.id] || 0), 0);
    const newCount = tickets.filter((t) => newTicketIds.includes(t.id)).length;
    return { unreadCount, newCount, total: unreadCount + newCount };
  };

  const createdBadge = getTabBadge(createdTickets);
  const assignedBadge = getTabBadge(assignedTickets);
  const participatedBadge = getTabBadge(participatedTickets);

  const tickets = tab === 'created' ? createdTickets : tab === 'assigned' ? assignedTickets : participatedTickets;

  // 渲染 Segmented 标签（内嵌角标）
  const makeTabLabel = (
    icon: React.ReactNode,
    label: string,
    count: number,
    badge: { total: number; newCount: number; unreadCount: number }
  ) => (
    <span style={{ display: 'inline-flex', alignItems: 'center', gap: 6 }}>
      {icon}
      {label} ({count})
      {badge.total > 0 && (
        <span style={{
          display: 'inline-flex',
          alignItems: 'center',
          gap: 3,
          background: badge.newCount > 0 ? '#ff4d4f' : '#1677ff',
          color: '#fff',
          borderRadius: 10,
          padding: '0 7px',
          fontSize: 11,
          fontWeight: 700,
          lineHeight: '18px',
          minWidth: 18,
          justifyContent: 'center',
          animation: 'pulse 1.5s infinite',
        }}>
          {badge.total}
        </span>
      )}
    </span>
  );

  const renderTicketCard = (ticket: any) => {
    const unread = unreadMap[ticket.id] || 0;
    const isNew = newTicketIds.includes(ticket.id);

    return (
      <Col xs={24} sm={12} lg={8} key={ticket.id}>
        <div style={{ position: 'relative' }}>
          {/* 新工单角标 */}
          {isNew && (
            <span style={{
              position: 'absolute',
              top: -6,
              right: -6,
              background: '#ff4d4f',
              color: '#fff',
              fontSize: 10,
              fontWeight: 700,
              borderRadius: '10px 10px 10px 2px',
              padding: '2px 8px',
              zIndex: 2,
              boxShadow: '0 2px 8px rgba(255,77,79,0.5)',
              animation: 'pulse 1.5s infinite',
            }}>NEW</span>
          )}
          <div className="ticket-card" onClick={() => {
          // 进入工单时同时清晎 NEW 标记和未读数
          if (newTicketIds.includes(ticket.id)) clearNewTicket(ticket.id);
          clearUnread(ticket.id);
          navigate(`/tickets/${ticket.id}`);
        }} style={{ cursor: 'pointer' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 8, alignItems: 'center' }}>
              <span style={{ fontSize: 12, color: 'var(--text-muted)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap', flex: 1 }}>{ticket.ticketNo}</span>
              <div style={{ display: 'flex', alignItems: 'center', gap: 6, flexShrink: 0 }}>
                {/* 未读消息角标 */}
                {unread > 0 && (
                  <Badge count={unread} size="small" style={{ boxShadow: 'none' }}>
                    <MessageOutlined style={{ color: '#1677ff', fontSize: 14 }} />
                  </Badge>
                )}
                <Tag color={statusMap[ticket.status]?.color} style={{ margin: 0 }}>{statusMap[ticket.status]?.text}</Tag>
              </div>
            </div>
            <h4 style={{ marginBottom: 8, fontSize: 15, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{ticket.title}</h4>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 12, color: 'var(--text-muted)' }}>
              <span>
                {ticket.category1 ? (
                  <span style={{ display: 'inline-flex', gap: 4, alignItems: 'center', flexWrap: 'wrap' }}>
                    <Tag color={ticket.category1 === '硬件设备' ? 'volcano' : 'geekblue'} style={{ fontSize: 11, margin: 0 }}>
                      {ticket.category2 ? `${ticket.category1} · ${ticket.category2}` : ticket.category1}
                    </Tag>
                    {ticket.category3 && <Tag style={{ margin: 0, fontSize: 11 }}>{ticket.category3}</Tag>}
                  </span>
                ) : (
                  <Tag style={{ fontSize: 11 }}>{typeMap[ticket.type] || ticket.type}</Tag>
                )}
              </span>
              <span>{new Date(ticket.createdAt).toLocaleDateString('zh-CN')}</span>
            </div>
            {tab === 'created' && (
              <div style={{ marginTop: 8, fontSize: 12, color: 'var(--text-secondary)' }}>
                {ticket.assignee ? `接单人: ${ticket.assignee.realName || ticket.assignee.displayName || ticket.assignee.username}` : '尚未被接单'}
              </div>
            )}
            {tab === 'assigned' && ticket.status === 'pending' && (
              <Button size="small" type="primary" block icon={<CheckOutlined />}
                onClick={(e) => { e.stopPropagation(); handleAssign(ticket.id); }}
                style={{ marginTop: 10, background: 'var(--info)', border: 'none', borderRadius: 6, fontSize: 12 }}>
                接单
              </Button>
            )}
            {tab === 'participated' && ticket.status !== 'closed' && (
              <Button size="small" type="primary" block icon={<LoginOutlined />}
                onClick={(e) => { e.stopPropagation(); navigate(`/tickets/${ticket.id}`); }}
                style={{ marginTop: 10, background: 'var(--primary)', border: 'none', borderRadius: 6, fontSize: 12 }}>
                进入会话
              </Button>
            )}
            {ticket.status === 'closed' && (
              <Button size="small" type="primary" block icon={<RobotOutlined />}
                onClick={(e) => { e.stopPropagation(); navigate(`/tickets/${ticket.id}`); }}
                style={{ marginTop: 10, background: 'linear-gradient(90deg, #7c3aed, #4f46e5)', border: 'none', borderRadius: 6, fontSize: 12 }}>
                📝 生成知识库
              </Button>
            )}
          </div>
        </div>
      </Col>
    );
  };

  return (
    <div className="fade-in">
      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 1; transform: scale(1); }
          50% { opacity: 0.85; transform: scale(1.08); }
        }
      `}</style>

      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 20, flexWrap: 'wrap', gap: 12 }}>
        <div>
          <h2 style={{ fontSize: 22, fontWeight: 600, margin: 0 }}>
            个人主页 · {user?.realName || user?.displayName || user?.username}
          </h2>
          {(user?.employeeId || user?.department || user?.position) && (
            <div style={{ marginTop: 8, display: 'flex', gap: 8, flexWrap: 'wrap' }}>
              {user.employeeId && <Tag color="blue" bordered={false}>工号: {user.employeeId}</Tag>}
              {user.department && <Tag color="cyan" bordered={false}>部门: {user.department}</Tag>}
              {user.position && <Tag color="geekblue" bordered={false}>职位: {user.position}</Tag>}
            </div>
          )}
        </div>
        <Button type="primary" icon={<PlusOutlined />} onClick={() => setCreateModalOpen(true)}>
          新建工单
        </Button>
      </div>

      <Segmented
        value={tab}
        onChange={(v) => setTab(v as string)}
        options={[
          {
            value: 'created',
            label: makeTabLabel(<FileTextOutlined />, '我申请的', createdTickets.length, createdBadge),
          },
          {
            value: 'assigned',
            label: makeTabLabel(<CustomerServiceOutlined />, '我接手的', assignedTickets.length, assignedBadge),
          },
          {
            value: 'participated',
            label: makeTabLabel(<TeamOutlined />, '我参与的', participatedTickets.length, participatedBadge),
          },
        ]}
        style={{ marginBottom: 20 }}
        block
      />

      {tickets.length === 0 ? (
        <Card style={{ borderRadius: 12 }}>
          <Empty description={tab === 'created' ? '还没有发起过工单' : tab === 'assigned' ? '还没有接手过工单' : '还没有参与任何工单'} />
        </Card>
      ) : (
        <Row gutter={[16, 16]}>
          {tickets.map(renderTicketCard)}
        </Row>
      )}

      {/* 创建工单弹窗 */}
      <Modal title="创建技术支持工单" open={createModalOpen}
        onCancel={() => { setCreateModalOpen(false); createForm.resetFields(); }}
        onOk={() => createForm.submit()}
        width={600} okText="提交" cancelText="取消">
        <Form form={createForm} layout="vertical" onFinish={handleCreate} style={{ marginTop: 16 }}>
          <Form.Item name="title" label="标题" rules={[{ required: true, message: '请输入标题' }]}>
            <Input placeholder="请简要描述问题" />
          </Form.Item>
          <Form.Item name="description" label="问题描述" rules={[{ required: true, message: '请描述问题' }]}>
            <Input.TextArea rows={4} placeholder="请详细描述遇到的问题..." />
          </Form.Item>
          <Row gutter={16}>
            <Col xs={24} sm={12}>
              {categoryTree.length > 0 ? (
                <Form.Item name="categoryPath" label="工单分类" rules={[{ required: true, message: '请选择工单分类' }]}>
                  <Cascader
                    options={categoryTree}
                    placeholder="支持类型 / 技术方向 / 品牌"
                    showSearch={{ filter: (input: string, path: any[]) => path.some((opt: any) => opt.label.toLowerCase().includes(input.toLowerCase())) }}
                    changeOnSelect
                  />
                </Form.Item>
              ) : (
                <Form.Item name="type" label="问题类型" initialValue="other">
                  <Select>
                    <Option value="software">软件问题</Option>
                    <Option value="hardware">硬件问题</Option>
                    <Option value="network">网络问题</Option>
                    <Option value="security">安全问题</Option>
                    <Option value="database">数据库</Option>
                    <Option value="other">其他</Option>
                  </Select>
                </Form.Item>
              )}
            </Col>
            <Col xs={24} sm={12}>
              <Form.Item name="customerName" label="客户名称">
                <Input placeholder="请输入客户名称" />
              </Form.Item>
            </Col>
          </Row>
          <Form.Item name="serviceNo" label="服务单号">
            <Input placeholder="关联的服务单号 (选填)" />
          </Form.Item>
          <Form.Item name="assigneeId" label="指定接单人">
            <Select showSearch allowClear
              placeholder="留空则发布到工单广场，输入姓名/用户名可定向派单"
              filterOption={false} onSearch={handleAssigneeSearch}
              loading={assigneeSearching} options={assigneeOptions}
              notFoundContent={assigneeSearching ? '搜索中...' : '输入用户名或姓名搜索'}
            />
          </Form.Item>
        </Form>
      </Modal>
    </div>
  );
};

export default ProfilePage;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Card, Row, Col, Breadcrumb, Empty, Spin, Segmented, Drawer, Button, Typography, Table, Tag, Statistic, Modal, Radio, DatePicker, Space } from 'antd';
import type { RadioChangeEvent } from 'antd';
import {
  BarChartOutlined, TeamOutlined, ArrowsAltOutlined, ArrowRightOutlined, SyncOutlined,
  FileTextOutlined, ClockCircleOutlined, CheckCircleOutlined, DownloadOutlined
} from '@ant-design/icons';
import ReactECharts from 'echarts-for-react';
import { reportAPI, ticketsAPI } from '../../services/api';
import { message } from 'antd';
import dayjs from 'dayjs';
import type { Dayjs } from 'dayjs';
import type {
  ApiResponse,
  ReportCategoryStats,
  ReportCrossMatrix,
  ReportDimension,
  ReportStatItem,
  ReportSummary,
  ReportTimeSeriesItem,
} from '../../types/api';
import type { Ticket } from '../../types/ticket';

const { Title, Text } = Typography;

interface TicketDrawerState {
  open: boolean;
  title: string;
  category3: string;
  role: 'creator' | 'assignee' | '';
  userId: number;
}

interface ChartClickParam {
  name: string;
  dataIndex: number;
}

interface ChartColorStop {
  offset: number;
  color: string;
}

/** 读取 CSS 变量的实际计算值，供 ECharts 使用（ECharts 不支持 var(--xxx) 语法） */
function cssVar(name: string): string {
  return getComputedStyle(document.documentElement).getPropertyValue(name).trim() || '#888';
}

const ReportsPage: React.FC = () => {
  // ================= Control State =================
  const [loading, setLoading] = useState(false);
  const [exportLoading, setExportLoading] = useState(false);
  const [viewLevel, setViewLevel] = useState<1 | 2 | 3>(1);
  const [ticketDrawerState, setTicketDrawerState] = useState<TicketDrawerState>({ open: false, title: '', category3: '', role: '', userId: 0 });

  // Drilldown Paths
  const [drillPath, setDrillPath] = useState<{ category1?: string, category2?: string }>({});

  // ================= Dashboard Data (Level 1) =================
  const [summary, setSummary] = useState<ReportSummary | null>(null);
  const [trendDimension, setTrendDimension] = useState<ReportDimension>('day');
  const [timeSeries, setTimeSeries] = useState<ReportTimeSeriesItem[]>([]);
  const [categoryStats, setCategoryStats] = useState<ReportCategoryStats>({ category1: [], category2: [] });

  // ================= Drilldown Data (Level 2 & 3) =================
  const [level2Data, setLevel2Data] = useState<ReportStatItem[]>([]);
  const [level2Matrices, setLevel2Matrices] = useState<Record<string, ReportStatItem[]>>({});
  const [level3Data, setLevel3Data] = useState<ReportStatItem[]>([]);
  const [level3Matrices, setLevel3Matrices] = useState<Record<string, ReportCrossMatrix>>({});

  // ================= User Tickets Data (Level 4 Drawer) =================
  const [userTickets, setUserTickets] = useState<Ticket[]>([]);
  const [userTicketsLoading, setUserTicketsLoading] = useState(false);

  // ================= Export Modal State =================
  const [exportModalOpen, setExportModalOpen] = useState(false);
  const [selectedYear, setSelectedYear] = useState<string>('all');
  const [selectedQuarter, setSelectedQuarter] = useState<string>('all');
  const [selectedMonth, setSelectedMonth] = useState<string>('all');
  const [customDateRange, setCustomDateRange] = useState<[Dayjs, Dayjs] | null>(null);

  const currentYear = dayjs().year();
  const recentYears = [currentYear, currentYear - 1, currentYear - 2];

  // Theme key to force chart re-render on theme switch
  const [themeKey, setThemeKey] = useState(0);
  useEffect(() => {
    const obs = new MutationObserver(() => setThemeKey(k => k + 1));
    obs.observe(document.documentElement, { attributes: true, attributeFilter: ['class', 'data-theme'] });
    return () => obs.disconnect();
  }, []);

  // Pre-compute colors per render cycle for ECharts
  const themeColors = useMemo(() => ({
    textPrimary: cssVar('--text-primary'),
    textSecondary: cssVar('--text-secondary'),
    bgPrimary: cssVar('--bg-primary'),
    bgSecondary: cssVar('--bg-secondary'),
    bgCard: cssVar('--bg-card'),
    border: cssVar('--border'),
  }), [themeKey]); // eslint-disable-line react-hooks/exhaustive-deps

  // ================= Initial Load =================
  const loadDashboard = useCallback(async () => {
    setLoading(true);
    try {
      const [sumRes, catRes] = await Promise.all([
        reportAPI.getSummary(),
        reportAPI.getCategoryStats()
      ]);
      if (sumRes.code === 0) setSummary(sumRes.data);
      if (catRes.code === 0) setCategoryStats(catRes.data);
    } catch {}
    setLoading(false);
  }, []);

  const loadTimeSeries = useCallback(async () => {
    try {
      const res = await reportAPI.getTimeSeries(trendDimension);
      if (res.code === 0) setTimeSeries(res.data);
    } catch {}
  }, [trendDimension]);

  useEffect(() => { loadDashboard(); }, [loadDashboard]);
  useEffect(() => { loadTimeSeries(); }, [loadTimeSeries]);

  // ================= Event Handlers =================
  const handleCat1Click = async (cat1Name: string) => {
    setDrillPath({ category1: cat1Name });
    setViewLevel(2);
    setLoading(true);
    try {
      const res = await reportAPI.getCategory2Stats(cat1Name);
      if (res.code === 0) {
        setLevel2Data(res.data);
        const matrixPromises: Array<Promise<ApiResponse<ReportStatItem[]>>> = res.data.map((cat) =>
          reportAPI.getCategory3Stats(cat.name).catch(() => ({ code: 1, data: [] })),
        );
        const matrixRes = await Promise.all(matrixPromises);
        const mMap: Record<string, ReportStatItem[]> = {};
        res.data.forEach((cat, i) => {
           if (matrixRes[i].code === 0) mMap[cat.name] = matrixRes[i].data;
        });
        setLevel2Matrices(mMap);
      }
    } catch {}
    setLoading(false);
  };

  const handleCat2Click = async (cat2Name: string) => {
    setDrillPath({ ...drillPath, category2: cat2Name });
    setViewLevel(3);
    setLoading(true);
    try {
      const res = await reportAPI.getCategory3Stats(cat2Name);
      if (res.code === 0) {
        setLevel3Data(res.data);
        // 传入 parentCategory=cat2Name，确保只统计当前 category2 下的品牌数据
        const matrixPromises: Array<Promise<ApiResponse<ReportCrossMatrix>>> = res.data.map((cat) =>
          reportAPI
            .getCrossMatrix(cat.name, 'category3', 5, { category2: cat2Name })
            .catch(() => ({ code: 1, data: { supporters: [], requesters: [] } })),
        );
        const matrixRes = await Promise.all(matrixPromises);
        const mMap: Record<string, ReportCrossMatrix> = {};
        res.data.forEach((cat, i) => {
           if (matrixRes[i].code === 0) mMap[cat.name] = matrixRes[i].data;
        });
        setLevel3Matrices(mMap);
      }
    } catch {}
    setLoading(false);
  };

  const handleUserClick = async (userId: number, userName: string, role: 'creator' | 'assignee', category3Name: string) => {
    setTicketDrawerState({ open: true, title: `${userName} 的 ${category3Name} [${role==='creator' ? '提单' : '接单'}] 列表`, category3: category3Name, role, userId });
    setUserTicketsLoading(true);
    try {
      const filter = {
        category3: category3Name,
        pageSize: 15,
        ...(role === 'creator' ? { creatorId: userId } : { assigneeId: userId }),
      };
      const res = await ticketsAPI.getAll(filter);
      if (res.code === 0) setUserTickets(res.data.items);
    } catch {}
    setUserTicketsLoading(false);
  };

  const handleYearChange = (e: RadioChangeEvent) => {
    setSelectedYear(e.target.value);
    setSelectedQuarter('all');
    setSelectedMonth('all');
  };

  const handleQuarterChange = (e: RadioChangeEvent) => {
    setSelectedQuarter(e.target.value);
    setSelectedMonth('all');
  };

  const executeExport = async () => {
    let startDate = '';
    let endDate = '';
    let label = '全部';

    if (selectedYear === 'custom') {
      if (!customDateRange || customDateRange.length < 2) {
        return message.warning('请选择自定义时间范围');
      }
      startDate = customDateRange[0].format('YYYY-MM-DD');
      endDate = customDateRange[1].format('YYYY-MM-DD');
      label = `${startDate}_至_${endDate}`;
    } else if (selectedYear !== 'all') {
      const yearStr = selectedYear;
      if (selectedQuarter === 'all') {
        startDate = `${yearStr}-01-01`;
        endDate = `${yearStr}-12-31`;
        label = `${yearStr}全年`;
      } else {
        const q = parseInt(selectedQuarter.replace('Q', ''));
        if (selectedMonth === 'all') {
          startDate = dayjs(`${yearStr}-${(q - 1) * 3 + 1}-01`).format('YYYY-MM-DD');
          endDate = dayjs(startDate).add(2, 'month').endOf('month').format('YYYY-MM-DD');
          label = `${yearStr}年Q${q}`;
        } else {
          const m = selectedMonth;
          startDate = dayjs(`${yearStr}-${m}-01`).format('YYYY-MM-DD');
          endDate = dayjs(startDate).endOf('month').format('YYYY-MM-DD');
          label = `${yearStr}年${m}月`;
        }
      }
    }

    setExportLoading(true);
    try {
      const res = await reportAPI.exportXlsx({ startDate, endDate });
      const blob = new Blob([res], { type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet' });
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `工单数据导出_${label}_${dayjs().format('YYYYMMDD_HHmmss')}.xlsx`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);
      message.success('导出成功');
      setExportModalOpen(false);
    } catch {
      message.error('导出失败，请重试');
    }
    setExportLoading(false);
  };

  // ================= Theme-aware Chart Helpers =================
  const chartTextStyle = { color: themeColors.textSecondary };

  const getTrendOption = () => ({
    tooltip: { trigger: 'axis', axisPointer: { type: 'cross' }, backgroundColor: themeColors.bgSecondary, borderColor: themeColors.border, textStyle: { color: themeColors.textPrimary } },
    xAxis: { type: 'category', data: timeSeries.map((t) => t.date), axisLabel: chartTextStyle },
    yAxis: { type: 'value', splitLine: { lineStyle: { type: 'dashed', color: themeColors.border } }, axisLabel: chartTextStyle },
    series: [
      {
        name: '工单柱体',
        type: 'bar',
        barWidth: '30%',
        itemStyle: { color: 'rgba(56, 189, 248, 0.25)', borderRadius: [4, 4, 0, 0], borderColor: 'rgba(56, 189, 248, 0.5)', borderWidth: 1 },
        label: { show: true, position: 'top', color: '#0ea5e9' },
        data: timeSeries.map((t) => t.count),
      },
      {
        name: '工单趋势',
        type: 'line',
        itemStyle: { color: '#8b5cf6' },
        areaStyle: {
          color: { type: 'linear', x: 0, y: 0, x2: 0, y2: 1, colorStops: [{ offset: 0, color: 'rgba(139, 92, 246, 0.5)' }, { offset: 1, color: 'rgba(139, 92, 246, 0.0)' }] }
        },
        smooth: true,
        data: timeSeries.map((t) => t.count),
      }
    ],
    grid: { left: 40, right: 20, bottom: 20, top: 20, containLabel: true }
  });

  const getCat1PieOption = () => ({
    tooltip: { trigger: 'item', formatter: '{b}: {c} ({d}%)', backgroundColor: themeColors.bgSecondary, borderColor: themeColors.border, textStyle: { color: themeColors.textPrimary } },
    color: ['#6366f1', '#06b6d4', '#f59e0b', '#10b981'],
    series: [{
      type: 'pie', radius: ['45%', '65%'], center: ['50%', '50%'],
      itemStyle: { borderRadius: 4, borderColor: themeColors.bgCard, borderWidth: 2 },
      label: { show: true, position: 'outside', color: themeColors.textPrimary, formatter: '{b}' },
      labelLine: { length: 10, length2: 15 },
      data: categoryStats.category1.length > 0 ? categoryStats.category1 : [{ name: '暂无数据', value: 0 }]
    }]
  });

  const getCat2BarOption = () => ({
    tooltip: { trigger: 'axis', axisPointer: { type: 'shadow' }, backgroundColor: themeColors.bgSecondary, borderColor: themeColors.border, textStyle: { color: themeColors.textPrimary } },
    xAxis: { type: 'value', splitLine: { show: false }, axisLabel: { show: false } },
    yAxis: { type: 'category', inverse: true, data: categoryStats.category2.map((c) => c.name), axisLabel: { color: themeColors.textPrimary, width: 90, overflow: 'truncate' }, axisLine: { show: false }, axisTick: { show: false } },
    series: [{
      type: 'bar', barWidth: 12,
      itemStyle: { borderRadius: 6, color: { type: 'linear', x: 0, y: 0, x2: 1, y2: 0, colorStops: [{ offset: 0, color: '#3b82f6' }, { offset: 1, color: '#06b6d4' }] } },
      label: { show: true, position: 'right', color: themeColors.textSecondary },
      data: categoryStats.category2.map((c) => c.value),
    }],
    grid: { left: 0, right: 30, bottom: 0, top: 0, containLabel: true }
  });

  const getBarOption = <T extends object>(data: T[], valKey: keyof T, nameKey: keyof T, colorStops: ChartColorStop[]) => ({
    tooltip: { trigger: 'item', backgroundColor: themeColors.bgSecondary, borderColor: themeColors.border, textStyle: { color: themeColors.textPrimary } },
    xAxis: { type: 'value', splitLine: { show: false }, axisLabel: { show: false } },
    yAxis: { type: 'category', inverse: true, data: data.map((c) => String(c[nameKey])), axisLabel: { color: themeColors.textPrimary }, axisLine: { show: false }, axisTick: { show: false } },
    series: [{
      type: 'bar', barWidth: 12,
      itemStyle: { borderRadius: 6, color: { type: 'linear', x: 0, y: 0, x2: 1, y2: 0, colorStops } },
      label: { show: true, position: 'right', color: themeColors.textSecondary },
      data: data.map((c) => Number(c[valKey]) || 0),
    }],
    grid: { left: 10, right: 30, bottom: 0, top: 0, containLabel: true }
  });

  // ================= MAIN RENDER =================
  return (
    <div className="fade-in page-flex-layout" style={{ maxWidth: 1600, margin: '0 auto', width: '100%' }}>

      <div className="page-sticky-header">
      {/* Dynamic Header Breadcrumb based on Level */}
      <div style={{ marginBottom: 24, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <Breadcrumb separator=">" items={[
          { title: <a style={{ fontSize: 22, fontWeight: 600, color: viewLevel === 1 ? 'var(--text-primary)' : 'var(--text-secondary)' }} onClick={() => setViewLevel(1)}>报表总览</a> },
          ...(viewLevel >= 2 ? [{ title: <a style={{ fontSize: 18, fontWeight: 500, color: viewLevel === 2 ? 'var(--text-primary)' : 'var(--text-secondary)' }} onClick={() => setViewLevel(2)}>{drillPath.category1}领域</a> }] : []),
          ...(viewLevel >= 3 ? [{ title: <span style={{ fontSize: 18, fontWeight: 500, color: 'var(--text-primary)' }}>{drillPath.category2}排行</span> }] : []),
        ]} />
        <div style={{ display: 'flex', gap: 8 }}>
          <Button 
            icon={<DownloadOutlined />} 
            onClick={() => setExportModalOpen(true)}
          >
            📥 导出工单数据
          </Button>
          <Button icon={<SyncOutlined />} onClick={() => loadDashboard()}>刷新数据</Button>
        </div>
        </div>
      </div>
      <div className="page-scroll-content" style={{ padding: '0 16px 24px' }}>

      <Spin spinning={loading}>

        {/* Level 1: Dashboard */}
        {viewLevel === 1 && (
          <div className="view-level-1">
            {/* Top Summary Widgets */}
            {summary && (
              <Row gutter={[24, 24]} style={{ marginBottom: 24 }}>
                <Col xs={12} sm={6}>
                  <Card style={{ borderRadius: 12 }}>
                    <Statistic title={<Text type="secondary"><FileTextOutlined /> 总工单数</Text>} value={summary.total || 0} valueStyle={{ fontWeight: 'bold' }} />
                  </Card>
                </Col>
                <Col xs={12} sm={6}>
                  <Card style={{ borderRadius: 12 }}>
                    <Statistic title={<Text type="secondary"><ClockCircleOutlined /> 待处理</Text>} value={summary.pending || 0} valueStyle={{ color: '#eab308', fontWeight: 'bold' }} />
                  </Card>
                </Col>
                <Col xs={12} sm={6}>
                  <Card style={{ borderRadius: 12 }}>
                    <Statistic title={<Text type="secondary"><CheckCircleOutlined /> 已关单</Text>} value={summary.closed || 0} valueStyle={{ color: '#10b981', fontWeight: 'bold' }} />
                  </Card>
                </Col>
                <Col xs={12} sm={6}>
                  <Card style={{ borderRadius: 12 }}>
                    <Statistic title={<Text type="secondary"><ClockCircleOutlined /> 平均处理时长</Text>} value={summary.avgHours || 0} precision={1} suffix="小时" valueStyle={{ color: '#0ea5e9', fontWeight: 'bold' }} />
                  </Card>
                </Col>
              </Row>
            )}

            <Row gutter={[24, 24]}>
              <Col span={24}>
                <Card style={{ borderRadius: 12 }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 24 }}>
                    <Title level={4} style={{ margin: 0 }}>工单趋势分析</Title>
                    <Segmented value={trendDimension} onChange={(v) => setTrendDimension(v as ReportDimension)} options={[{label:'30天', value:'day'}, {label:'12个月', value:'month'}, {label:'6个季度', value:'quarter'}, {label:'3年', value:'year'}]} />
                  </div>
                  <ReactECharts key={`trend-${themeKey}`} option={getTrendOption()} style={{ height: 350 }} />
                </Card>
              </Col>

              <Col xs={24} lg={8}>
                <Card title={<span><BarChartOutlined /> 软硬大类分布</span>} style={{ borderRadius: 12, height: '100%' }}>
                  <Text type="secondary" style={{ display: 'block', marginBottom: 16, fontSize: 12 }}>提示：点击饼图区域可下钻至 Level 2 的详细技术方向报表。</Text>
                  <ReactECharts key={`pie-${themeKey}`} option={getCat1PieOption()} style={{ height: 300 }} onEvents={{ click: (param: ChartClickParam) => handleCat1Click(param.name) }} />
                </Card>
              </Col>

              <Col xs={24} lg={16}>
                <Card title={<span><BarChartOutlined /> 技术方向分布 (Top10)</span>} style={{ borderRadius: 12, height: '100%' }}>
                  <Text type="secondary" style={{ display: 'block', marginBottom: 16, fontSize: 12 }}>提示：点击柱状图任意选项可直接下钻至 Level 3 的人员绩效矩阵。</Text>
                  <ReactECharts key={`bar-${themeKey}`} option={getCat2BarOption()} style={{ height: 300 }} onEvents={{ click: (param: ChartClickParam) => handleCat2Click(param.name) }} />
                </Card>
              </Col>
            </Row>
          </div>
        )}

        {/* Level 2: Specific Category 1 -> All Category 2s Cards & Cat3 pies/bars */}
        {viewLevel === 2 && (
          <Row gutter={[24, 24]}>
            <Col span={24}>
              <Title level={4}><ArrowsAltOutlined /> [{drillPath.category1}] 下属技术架构分布</Title>
              <Text type="secondary" style={{ display: 'block', marginBottom: 24 }}>展示该领域下所有的技术分类及其子品牌的统计。点击技术分类卡片可下钻人员明细。</Text>
            </Col>
            {level2Data.length === 0 ? <Empty image={Empty.PRESENTED_IMAGE_SIMPLE} description="该分类下无历史数据" /> : null}
            {level2Data.map((cat2, idx) => (
              <Col xs={24} lg={12} xl={8} key={idx}>
                <Card hoverable onClick={() => handleCat2Click(cat2.name)} style={{ borderRadius: 12, height: '100%', cursor: 'pointer', transition: 'all 0.3s' }}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
                    <Title level={5} style={{ margin: 0, color: '#0ea5e9' }}>{cat2.name}</Title>
                    <div style={{ fontSize: 24, fontWeight: 'bold' }}>{cat2.value} <span style={{ fontSize: 12, color: 'var(--text-secondary)' }}>单</span></div>
                  </div>
                  <div style={{ background: 'var(--bg-primary)', borderRadius: 8, padding: 12, height: 200, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                     {level2Matrices[cat2.name] && level2Matrices[cat2.name].length > 0 ? (
                       <ReactECharts key={`l2-${idx}-${themeKey}`} option={getBarOption(level2Matrices[cat2.name], 'value', 'name', [{offset:0, color:'#a855f7'}, {offset:1, color:'#d946ef'}])} style={{ height: '100%', width: '100%' }} />
                     ) : (
                       <Text type="secondary">暂无子品牌数据</Text>
                     )}
                  </div>
                  <div style={{ textAlign: 'right', marginTop: 12 }}><Text style={{ color: 'var(--primary)', fontSize: 12 }}>点击深入 Level 3 <ArrowRightOutlined/></Text></div>
                </Card>
              </Col>
            ))}
          </Row>
        )}

        {/* Level 3: Specific Category 2 -> All Category 3s Cards & Personnel Matrices */}
        {viewLevel === 3 && (
          <Row gutter={[24, 24]}>
            <Col span={24}>
              <Title level={4}><TeamOutlined /> [{drillPath.category2}] 品牌维保绩效矩阵</Title>
              <Text type="secondary" style={{ display: 'block', marginBottom: 24 }}>展示该技术方向下，各个具体产品品牌的人员接单与提单情况排行。支持点击柱体人员名称查阅工单明细列表。</Text>
            </Col>
            {level3Data.length === 0 ? <Empty image={Empty.PRESENTED_IMAGE_SIMPLE} description="暂无对应品牌历史数据" /> : null}
            {level3Data.map((cat3, idx) => (
              <Col xs={24} xl={12} key={idx}>
                <Card style={{ borderRadius: 12, height: '100%' }}>
                   <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
                     <Title level={5} style={{ margin: 0, color: '#d97706' }}>{cat3.name}</Title>
                     <Tag color="purple">{cat3.value} 单总计</Tag>
                   </div>
                   <Row gutter={16}>
                     <Col span={12}>
                        <div style={{ padding: '8px 12px', background: 'var(--bg-primary)', borderRadius: '6px 6px 0 0', borderBottom: '2px solid #10b981', color: '#10b981', fontSize: 13, fontWeight: 'bold' }}>高效接单英雄榜 (Top 5)</div>
                        <div style={{ background: 'var(--bg-primary)', height: 260, padding: 8, borderRadius: '0 0 6px 6px' }}>
                           {level3Matrices[cat3.name]?.supporters?.length > 0 ? (
                             <ReactECharts key={`l3s-${idx}-${themeKey}`} onEvents={{ click: (p: ChartClickParam) => handleUserClick(level3Matrices[cat3.name].supporters[p.dataIndex].userId, p.name, 'assignee', cat3.name) }} option={getBarOption(level3Matrices[cat3.name].supporters, 'count', 'realName', [{offset:0, color:'#059669'}, {offset:1, color:'#34d399'}])} style={{ height: '100%', width: '100%' }} />
                           ) : <Empty image={Empty.PRESENTED_IMAGE_SIMPLE} description="" />}
                        </div>
                     </Col>
                     <Col span={12}>
                        <div style={{ padding: '8px 12px', background: 'var(--bg-primary)', borderRadius: '6px 6px 0 0', borderBottom: '2px solid #ef4444', color: '#ef4444', fontSize: 13, fontWeight: 'bold' }}>高频提单需求方 (Top 5)</div>
                        <div style={{ background: 'var(--bg-primary)', height: 260, padding: 8, borderRadius: '0 0 6px 6px' }}>
                           {level3Matrices[cat3.name]?.requesters?.length > 0 ? (
                             <ReactECharts key={`l3r-${idx}-${themeKey}`} onEvents={{ click: (p: ChartClickParam) => handleUserClick(level3Matrices[cat3.name].requesters[p.dataIndex].userId, p.name, 'creator', cat3.name) }} option={getBarOption(level3Matrices[cat3.name].requesters, 'count', 'realName', [{offset:0, color:'#b91c1c'}, {offset:1, color:'#f87171'}])} style={{ height: '100%', width: '100%' }} />
                           ) : <Empty image={Empty.PRESENTED_IMAGE_SIMPLE} description="" />}
                        </div>
                     </Col>
                   </Row>
                </Card>
              </Col>
            ))}
          </Row>
        )}

      </Spin>
      </div>

      {/* Level 4: Drawer showing specific User Tickets */}
      <Drawer
        title={ticketDrawerState.title}
        placement="right"
        width={900}
        onClose={() => setTicketDrawerState({ ...ticketDrawerState, open: false })}
        open={ticketDrawerState.open}
      >
        <Table 
          loading={userTicketsLoading}
          dataSource={userTickets}
          rowKey="id"
          pagination={{ pageSize: 15 }}
          size="small"
          columns={[
            { title: '工单号', dataIndex: 'ticketNo', key: 'ticketNo', width: 150, render: t => <Text style={{ color: 'var(--primary)', fontFamily: 'monospace' }}>{t}</Text> },
            { title: '大类/中类', key: 'cats', width: 140, render: (_, r) => <Text type="secondary">{r.category1} / {r.category2}</Text> },
            { title: '标题', dataIndex: 'title', key: 'title', render: t => <Text>{t}</Text> },
            { title: '时间', dataIndex: 'createdAt', key: 'createdAt', width: 160, render: t => <Text type="secondary">{dayjs(t).format('YYYY-MM-DD HH:mm')}</Text> },
            { title: '状态', dataIndex: 'status', key: 'status', width: 100, render: s => <Tag color={s === 'closed' ? 'success' : 'processing'}>{s==='closed'?'已关单':'处理中'}</Tag> },
            { title: '操作', key: 'action', width: 100, render: (_, r) => (
               <Button type="primary" size="small" onClick={() => window.open(`/tickets/${r.id}`, '_blank')}>追踪详情</Button>
            )}
          ]}
        />
      </Drawer>

      <Modal
        title="导出工单数据"
        open={exportModalOpen}
        onCancel={() => setExportModalOpen(false)}
        onOk={executeExport}
        confirmLoading={exportLoading}
        okText="确认导出"
        width={500}
      >
        <div style={{ padding: '12px 0' }}>
          <Space direction="vertical" size="large" style={{ width: '100%' }}>

            {/* 第一层：年份选择 */}
            <div>
              <Text strong style={{ display: 'block', marginBottom: 8, color: 'var(--text-secondary)' }}>1. 选择基础年份</Text>
              <Radio.Group value={selectedYear} onChange={handleYearChange} optionType="button" buttonStyle="solid">
                <Radio value="all">全部历史数据</Radio>
                {recentYears.map(y => <Radio key={y} value={y.toString()}>{y}年</Radio>)}
                <Radio value="custom">自定义跨度</Radio>
              </Radio.Group>
            </div>

            {/* 第二层：季度选择 */}
            {selectedYear !== 'all' && selectedYear !== 'custom' && (
              <div>
                <Text strong style={{ display: 'block', marginBottom: 8, color: 'var(--text-secondary)' }}>2. 选择目标季度</Text>
                <Radio.Group value={selectedQuarter} onChange={handleQuarterChange} optionType="button" buttonStyle="solid">
                  <Radio value="all">{selectedYear}全年</Radio>
                  <Radio value="Q1">第一季度</Radio>
                  <Radio value="Q2">第二季度</Radio>
                  <Radio value="Q3">第三季度</Radio>
                  <Radio value="Q4">第四季度</Radio>
                </Radio.Group>
              </div>
            )}

            {/* 第三层：月份选择 */}
            {selectedYear !== 'all' && selectedYear !== 'custom' && selectedQuarter !== 'all' && (
              <div>
                <Text strong style={{ display: 'block', marginBottom: 8, color: 'var(--text-secondary)' }}>3. 选择具体月份</Text>
                <Radio.Group value={selectedMonth} onChange={e => setSelectedMonth(e.target.value)} optionType="button" buttonStyle="solid">
                  <Radio value="all">{selectedQuarter}全季</Radio>
                  {(() => {
                    const q = parseInt(selectedQuarter.replace('Q', ''));
                    const startMonth = (q - 1) * 3 + 1;
                    return [startMonth, startMonth + 1, startMonth + 2].map(m => (
                      <Radio key={m} value={m.toString()}>{m}月</Radio>
                    ));
                  })()}
                </Radio.Group>
              </div>
            )}

            {/* 自定义日期选择器 */}
            {selectedYear === 'custom' && (
              <div>
                <Text strong style={{ display: 'block', marginBottom: 8, color: 'var(--text-secondary)' }}>选择日期范围</Text>
                <DatePicker.RangePicker 
                  style={{ width: '100%' }}
                  value={customDateRange}
                  onChange={(dates) => setCustomDateRange(dates && dates[0] && dates[1] ? [dates[0], dates[1]] : null)}
                />
              </div>
            )}

          </Space>
        </div>
      </Modal>
    </div>
  );
};
export default ReportsPage;

import React from 'react';
import { Button, Avatar, Tooltip, Popover } from 'antd';
import {
  ArrowLeftOutlined, TeamOutlined, LockOutlined, UnlockOutlined,
  DesktopOutlined, DownloadOutlined, InfoCircleOutlined,
  AudioOutlined,
} from '@ant-design/icons';
import type { Ticket } from '../../types/ticket';

interface ChatHeaderProps {
  ticket: Ticket;
  isMobile: boolean;
  externalTicketId?: string;
  user: any;
  socket: any;
  id: string | undefined;
  roomUsers: any[];
  canInvite: boolean;
  isRoomLocked: boolean;
  isExternalDisabled: boolean;
  exportingChat: boolean;
  screenShare: {
    isSharing: boolean;
    isViewing: boolean;
    hasActiveShare: boolean;
    sharerName: string;
    stopSharing: () => void;
    joinViewing: () => void;
    startSharing: () => void;
  };
  voiceChat: {
    isInVoice: boolean;
    isMuted: boolean;
    hasActiveVoice: boolean;
    voiceParticipants: Array<{ userId: number; userName: string }>;
    joinVoice: () => void;
    leaveVoice: () => void;
  };
  onNavigateBack: () => void;
  onOpenInfoDrawer: () => void;
  onExportChat: () => void;
  onToggleLock: () => void;
  onStopSharingAndExitSupport: () => void;
}

const ChatHeader: React.FC<ChatHeaderProps> = ({
  ticket,
  isMobile,
  externalTicketId,
  user,
  socket,
  id,
  roomUsers,
  canInvite,
  isRoomLocked,
  isExternalDisabled,
  exportingChat,
  screenShare,
  voiceChat,
  onNavigateBack,
  onOpenInfoDrawer,
  onExportChat,
  onToggleLock,
  onStopSharingAndExitSupport,
}) => {
  return (
    <div className="chat-header">
      {!externalTicketId && isMobile && (
        <Button type="text" icon={<ArrowLeftOutlined />}
          onClick={onNavigateBack}
          style={{ color: 'var(--text-primary)', marginRight: 8 }} />
      )}
      <span style={{ flex: 1, fontWeight: 500 }}>
        💬 {isMobile ? ticket.title : '实时沟通'}
      </span>

      {/* 在线用户头像组 */}
      {roomUsers.length > 0 && (
        <div style={{ display: 'flex', alignItems: 'center', gap: 2, marginRight: 8 }}>
          <TeamOutlined style={{ color: 'var(--text-muted)', fontSize: 14, marginRight: 4 }} />
          <Avatar.Group size={isMobile ? 22 : 26} max={{ count: isMobile ? 3 : 6, style: { background: 'linear-gradient(135deg, #4f46e5, #818cf8)', fontSize: 11 } }}>
            {roomUsers.map((u: any) => (
              <Popover 
                key={u.id} 
                title={`${u.name}${u.role === 'external' ? ' (外部)' : ''}`}
                content={
                  (!externalTicketId && canInvite && user?.id !== u.id) ? (
                    <Button size="small" danger type="text" onClick={() => {
                      socket?.emit('kickUser', { ticketId: Number(id), targetUserId: u.id });
                    }}>
                      踢出房间
                    </Button>
                  ) : null
                }
                trigger="hover"
              >
                <Avatar style={{ 
                  background: u.role === 'external' ? '#f59e0b' : 'linear-gradient(135deg, #4f46e5, #818cf8)', 
                  fontSize: 12,
                  cursor: (!externalTicketId && canInvite && user?.id !== u.id) ? 'pointer' : 'default'
                }}>
                  {u.name?.[0]?.toUpperCase() || '?'}
                </Avatar>
              </Popover>
            ))}
          </Avatar.Group>
        </div>
      )}

      {/* 锁定状态标识 */}
      {isRoomLocked && (
        <Tooltip title={`房间已锁定${isExternalDisabled ? '（外链已暂停）' : ''}`}>
          <LockOutlined style={{ color: '#ef4444', fontSize: 14, marginRight: 4 }} />
        </Tooltip>
      )}

      {/* 屏幕共享按钮 */}
      {['pending', 'in_progress', 'closing'].includes(ticket.status) && (
        <Tooltip title={
          screenShare.isSharing ? '点击停止分享屏幕'
          : screenShare.isViewing ? `正在观看 ${screenShare.sharerName} 的屏幕`
          : screenShare.hasActiveShare ? `${screenShare.sharerName} 正在共享屏幕 — 点击观看`
          : '分享屏幕'
        }>
          <Button
            type="text"
            size="small"
            icon={<DesktopOutlined />}
            style={{
              color: screenShare.isSharing || screenShare.isViewing
                ? '#10b981'
                : screenShare.hasActiveShare
                ? '#10b981'
                : 'var(--text-secondary)',
              fontSize: 14,
              animation: screenShare.hasActiveShare && !screenShare.isViewing && !screenShare.isSharing
                ? 'pulse-glow 2s ease-in-out infinite'
                : undefined,
            }}
            onClick={() => {
              if (screenShare.isSharing) {
                onStopSharingAndExitSupport();
              } else if (screenShare.hasActiveShare && !screenShare.isViewing) {
                screenShare.joinViewing();
              } else if (!screenShare.isViewing && !screenShare.hasActiveShare) {
                screenShare.startSharing();
              }
            }}
          />
        </Tooltip>
      )}

      {/* 语音通话按钮 */}
      {['pending', 'in_progress', 'closing'].includes(ticket.status) && (
        <Tooltip title={
          voiceChat.isInVoice ? '点击退出语音通话'
          : voiceChat.hasActiveVoice ? `${voiceChat.voiceParticipants.map(p => p.userName).join('、')} 正在语音通话 — 点击加入`
          : '加入语音通话'
        }>
          <Button
            type="text"
            size="small"
            icon={<AudioOutlined />}
            style={{
              color: voiceChat.isInVoice
                ? '#10b981'
                : voiceChat.hasActiveVoice
                ? '#10b981'
                : 'var(--text-secondary)',
              fontSize: 14,
              animation: voiceChat.hasActiveVoice && !voiceChat.isInVoice
                ? 'pulse-glow 2s ease-in-out infinite'
                : undefined,
            }}
            onClick={() => {
              if (voiceChat.isInVoice) {
                voiceChat.leaveVoice();
              } else {
                voiceChat.joinVoice();
              }
            }}
          />
        </Tooltip>
      )}

      {/* 导出按钮 — 仅内部受邀用户 */}
      {!externalTicketId && ticket && user?.role?.name !== 'external' && (
        <Tooltip title="导出聊天记录">
          <Button type="text" size="small" loading={exportingChat}
            icon={<DownloadOutlined />}
            style={{ color: 'var(--text-secondary)', fontSize: 14 }}
            onClick={onExportChat}
          />
        </Tooltip>
      )}

      {/* 锁定/解锁按钮 — 仅 creator / assignee */}
      {!externalTicketId && ticket && (Number(user?.id) === Number(ticket.creatorId) || Number(user?.id) === Number(ticket.assigneeId)) && (
        <Tooltip title={isRoomLocked ? '解锁房间' : '锁定房间'}>
          <Button type="text" size="small"
            icon={isRoomLocked ? <LockOutlined style={{ color: '#ef4444' }} /> : <UnlockOutlined />}
            style={{ color: isRoomLocked ? '#ef4444' : 'var(--text-secondary)', fontSize: 14 }}
            onClick={onToggleLock}
          />
        </Tooltip>
      )}

      {isMobile && (
        <Button type="text" icon={<InfoCircleOutlined />}
          onClick={onOpenInfoDrawer}
          style={{ color: 'var(--text-secondary)' }} />
      )}
    </div>
  );
};

export default ChatHeader;

